import{_ as t,c as e,o as r,a1 as d}from"./chunks/framework.DDNAyvCW.js";const o="/assets/hero.Bp2O22Zb.webp",u=JSON.parse('{"title":"Chaterm 文档","description":"","frontmatter":{},"headers":[],"relativePath":"docs/index.md","filePath":"docs/index.md"}'),i={name:"docs/index.md"};function h(s,a,l,n,c,p){return r(),e("div",null,a[0]||(a[0]=[d('<h1 id="chaterm-文档" tabindex="-1">Chaterm 文档 <a class="header-anchor" href="#chaterm-文档" aria-label="Permalink to &quot;Chaterm 文档&quot;">​</a></h1><p>Chaterm（/tʃɑːtɜːm/）是一款专为基础设施和云资源管理而构建的 AI 原生终端。它使工程师能够使用自然语言执行部署服务、故障排除和解决问题等复杂任务。</p><p>凭借其内置的专家级知识库和强大的代理推理能力，Chaterm 能够理解您的业务拓扑和运维目标。无需记忆复杂的命令、语法或参数，只需用自然语言描述您的任务目标，Chaterm 即可自主规划并执行跨多个主机或集群的复杂操作，包括代码构建、服务部署、故障诊断和自动回滚等关键流程。</p><p>Chaterm 依靠长期记忆和团队知识库，学习团队知识和用户习惯。它的目标是成为您智能的 DevOps 副驾驶，通过可重用的代理技能，帮助工程师更高效地完成日常任务。Chaterm 旨在降低不同技术栈带来的认知障碍，使每位开发人员都能快速获得高级 SRE 的运维经验和执行能力。</p><p><img src="'+o+'" alt=""></p><h2 id="快速开始" tabindex="-1">快速开始 <a class="header-anchor" href="#快速开始" aria-label="Permalink to &quot;快速开始&quot;">​</a></h2><ul><li><strong><a href="/docs/start/downloads/">下载 Chaterm</a></strong> -- 在 macOS、Windows 或 Linux 上安装 Chaterm</li><li><strong><a href="/docs/start/quickstart/">快速入门</a></strong> -- 连接您的第一台主机并运行首条 AI 辅助命令</li><li><strong><a href="/docs/hosts/add-personal">添加主机</a></strong> -- 注册个人服务器、堡垒机或路由器</li><li><strong><a href="/docs/ai/settings/">配置 AI</a></strong> -- 选择模型提供商并调整 AI 行为</li></ul><h2 id="核心特性" tabindex="-1">核心特性 <a class="header-anchor" href="#核心特性" aria-label="Permalink to &quot;核心特性&quot;">​</a></h2><h3 id="ai-agent-智能代理" tabindex="-1">AI Agent 智能代理 <a class="header-anchor" href="#ai-agent-智能代理" aria-label="Permalink to &quot;AI Agent 智能代理&quot;">​</a></h3><p>Agent 能理解目标，自主规划，并跨越多台主机完成问题分析与根因定位，自动闭环完成复杂的流程处理。</p><p>每一步操作均可审核与追溯，并支持快速日志回滚，让 AI 自动化在生产环境中更加安全可靠。</p><h3 id="智能命令推荐" tabindex="-1">智能命令推荐 <a class="header-anchor" href="#智能命令推荐" aria-label="Permalink to &quot;智能命令推荐&quot;">​</a></h3><p>结合用户习惯、本地记忆及当前服务器上下文，推荐最合适的命令，让终端输入更智能、更高效。</p><p>支持跨设备会话同步，并通过快捷命令与语音交互减少移动端输入成本，使远程运维更加流畅。</p><h3 id="用户知识库" tabindex="-1">用户知识库 <a class="header-anchor" href="#用户知识库" aria-label="Permalink to &quot;用户知识库&quot;">​</a></h3><p>支持导入技术手册、内部文档、脚本和白皮书，构建个人运维知识体系。</p><p>Chaterm 能理解当前基础设施上下文并精准检索相关知识，辅助任务决策与执行。</p><h3 id="agent-skill" tabindex="-1">Agent Skill <a class="header-anchor" href="#agent-skill" aria-label="Permalink to &quot;Agent Skill&quot;">​</a></h3><p>将复杂运维流程封装为可复用的 AI 技能，实现结构化、可靠的自动化执行。</p><p>帮助团队沉淀运维经验，使 AI 能安全、稳定地应用于真实生产环境。</p><h3 id="插件系统" tabindex="-1">插件系统 <a class="header-anchor" href="#插件系统" aria-label="Permalink to &quot;插件系统&quot;">​</a></h3><p>通过插件扩展，实现对公有云服务器与 Kubernetes 的统一认证、动态授权与安全加密连接。</p><p>提供更高效的资源访问体验，助力基础设施的集中化管理。</p><h2 id="热门页面" tabindex="-1">热门页面 <a class="header-anchor" href="#热门页面" aria-label="Permalink to &quot;热门页面&quot;">​</a></h2><table tabindex="0"><thead><tr><th>主题</th><th>描述</th></tr></thead><tbody><tr><td><a href="/docs/terminal/operations/">终端操作</a></td><td>掌握分屏、会话标签页和终端工作流</td></tr><tr><td><a href="/docs/ai/dialogs/">AI 对话</a></td><td>了解如何高效与 AI Agent 交互</td></tr><tr><td><a href="/docs/ai/llms/">模型列表</a></td><td>浏览支持的 LLM 提供商并配置您偏好的模型</td></tr><tr><td><a href="/docs/manage/keys/">密钥管理</a></td><td>安全管理 SSH 密钥和凭据</td></tr><tr><td><a href="/docs/mcp/usage/">MCP 使用指南</a></td><td>配置和使用 MCP 服务器以扩展上下文</td></tr><tr><td><a href="/docs/skills/usage/">Skills 使用指南</a></td><td>创建、导入和运行运维 Skill</td></tr><tr><td><a href="/docs/settings/shortcuts/">快捷键</a></td><td>查看和自定义快捷键绑定</td></tr><tr><td><a href="/docs/mobile/quickstart/">移动端快速入门</a></td><td>使用 Chaterm 移动端随时随地运维</td></tr><tr><td><a href="/docs/contributing/">贡献指南</a></td><td>参与 Chaterm 开发</td></tr></tbody></table><h2 id="定价" tabindex="-1">定价 <a class="header-anchor" href="#定价" aria-label="Permalink to &quot;定价&quot;">​</a></h2><p>Chaterm 提供免费版和面向团队及企业的付费方案。 查看 <a href="/docs/start/pricing/">定价页面</a> 了解功能详情和使用限制。</p><h2 id="获取帮助" tabindex="-1">获取帮助 <a class="header-anchor" href="#获取帮助" aria-label="Permalink to &quot;获取帮助&quot;">​</a></h2><ul><li>浏览侧边栏探索所有文档分类。</li><li>在 <a href="https://github.com/chaterm/chaterm" target="_blank" rel="noreferrer">GitHub</a> 上提交问题或功能建议。</li><li>通过 <a href="mailto:support@chaterm.ai" target="_blank" rel="noreferrer">support@chaterm.ai</a> 联系团队。</li></ul>',29)]))}const f=t(i,[["render",h]]);export{u as __pageData,f as default};
